const allItems = $input.all();
const prospectIds = allItems.map(item => 
  item.json.matched_prospects.map(prospect => prospect.prospect_id)
).flat();

return [{
  json: {
    prospect_ids: prospectIds
  }
}];

const items = [];

for (const item of $input.all()) {
  if (item.json.enriched_data && Array.isArray(item.json.enriched_data)) {
    for (const enrichedItem of item.json.enriched_data) {
      items.push({
        json: {
          prospect_id: enrichedItem.prospect_id,
          ...enrichedItem.data
        }
      });
    }
  }
}

return items;
